public class GsonCheckValidFloatingPointTest {

  @Test
  @DisplayName("checkValidFloatingPoint allows finite double values")
  void testCheckValidFloatingPoint_withFiniteValues() throws Exception {
    Method method = Gson.class.getDeclaredMethod("checkValidFloatingPoint", double.class);
    method.setAccessible(true);

    assertDoesNotThrow(() -> method.invoke(null, 0.0));
    assertDoesNotThrow(() -> method.invoke(null, 1.2345));
    assertDoesNotThrow(() -> method.invoke(null, -123.456));
    assertDoesNotThrow(() -> method.invoke(null, Double.MIN_VALUE));
    assertDoesNotThrow(() -> method.invoke(null, Double.MAX_VALUE));
  }

  @Test
  @DisplayName("checkValidFloatingPoint throws IllegalArgumentException for NaN")
  void testCheckValidFloatingPoint_withNaN() throws Exception {
    Method method = Gson.class.getDeclaredMethod("checkValidFloatingPoint", double.class);
    method.setAccessible(true);

    IllegalArgumentException thrown = assertThrows(IllegalArgumentException.class,
        () -> method.invoke(null, Double.NaN));

    // InvocationTargetException wraps the actual exception, so unwrap it
    Throwable cause = thrown.getCause();
    assertThrows(IllegalArgumentException.class, () -> { throw cause; });
  }

  @Test
  @DisplayName("checkValidFloatingPoint throws IllegalArgumentException for positive infinity")
  void testCheckValidFloatingPoint_withPositiveInfinity() throws Exception {
    Method method = Gson.class.getDeclaredMethod("checkValidFloatingPoint", double.class);
    method.setAccessible(true);

    IllegalArgumentException thrown = assertThrows(IllegalArgumentException.class,
        () -> method.invoke(null, Double.POSITIVE_INFINITY));

    Throwable cause = thrown.getCause();
    assertThrows(IllegalArgumentException.class, () -> { throw cause; });
  }

  @Test
  @DisplayName("checkValidFloatingPoint throws IllegalArgumentException for negative infinity")
  void testCheckValidFloatingPoint_withNegativeInfinity() throws Exception {
    Method method = Gson.class.getDeclaredMethod("checkValidFloatingPoint", double.class);
    method.setAccessible(true);

    IllegalArgumentException thrown = assertThrows(IllegalArgumentException.class,
        () -> method.invoke(null, Double.NEGATIVE_INFINITY));

    Throwable cause = thrown.getCause();
    assertThrows(IllegalArgumentException.class, () -> { throw cause; });
  }
